// Формируем тексты напоминаний
return $input.all().map(item => {
  const j = item.json;
  const dt = new Date(j.starts_at);
  const date = dt.toLocaleDateString('ru-RU', { day: '2-digit', month: '2-digit' });
  const time = dt.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });
  const isDay = j.kind === '24h';
  const text = isDay
    ? `Напоминаю: завтра ${date} в ${time} — ${j.service_title}.\nЕсли планы изменились — отмени через /cancel.`
    : `Через час, в ${time} — ${j.service_title}. Ждём!`;
  return {
    json: {
      booking_id: j.booking_id,
      tg_chat_id: j.tg_chat_id,
      kind: j.kind,
      text,
    }
  };
});
